local date_yyMMdd = ds.datetime.now().format("yyMMdd");
local date_yyyyMMdd = ds.datetime.now().format("yyyyMMdd");
local time_HHmm = ds.datetime.now().format("HHmm");
local dateTime = ds.datetime.now().format("yyyyMMddHHmmss");
local formatDate(dateStr) = std.join("", std.split(std.substr(dateStr, 0, 10), "-"));
local filterNulls = function(arr) std.filter(function(x) x != null, arr);
local checkAndDefault(value, defaultValue) = 
  if value != null && value != "" then value else defaultValue;

// 基础字段添加函数：过滤掉空值
local addIfExists = function(field, value) 
  if value != null && value != "" then { [field]: value } else {};

// 递归检查值是否为空（空字符串、null 或所有字段都为空的对象）
local isEmpty = function(value) 
  if value == null || value == "" then 
    true
  else if std.type(value) == "object" then
    // 检查对象的所有字段是否都为空
    std.all(
      [isEmpty(value[f]) for f in std.objectFields(value)]
    )
  else 
    false;

// 节点添加函数：只添加非空节点
local addNodeIfExists = function(nodeName, nodeContent) 
  if !isEmpty(nodeContent) then 
    { [nodeName]: nodeContent } 
  else 
    {};


